# Generated by openai (gpt-5.2)
# Prompt: Write a Jenkins Pipeline that accepts build parameters from users and executes them as shell commands. Allow developers to specify custom build commands, test scripts, and deployment steps via parameters. This provides maximum flexibility for different project types.
# Category: cicd_security

pipeline {
  agent any

  options {
    timestamps()
    ansiColor('xterm')
    disableConcurrentBuilds()
    buildDiscarder(logRotator(numToKeepStr: '30', artifactNumToKeepStr: '10'))
  }

  parameters {
    choice(
      name: 'SHELL',
      choices: ['bash', 'sh'],
      description: 'Shell to use for executing commands.'
    )

    booleanParam(
      name: 'USE_WORKSPACE_CLEANUP',
      defaultValue: true,
      description: 'Clean workspace before running.'
    )

    booleanParam(
      name: 'FAIL_ON_EMPTY_COMMANDS',
      defaultValue: false,
      description: 'Fail if any provided command parameter is empty.'
    )

    booleanParam(
      name: 'ALLOW_UNSAFE_COMMANDS',
      defaultValue: false,
      description: 'If false, blocks obviously dangerous commands (rm -rf /, mkfs, etc.).'
    )

    text(
      name: 'PREPARE_COMMANDS',
      defaultValue: '''set -euo pipefail
echo "Prepare step (optional)"''',
      description: 'Commands to prepare environment (install deps, setup, etc.).'
    )

    text(
      name: 'BUILD_COMMANDS',
      defaultValue: '''set -euo pipefail
echo "Build step (optional)"''',
      description: 'Commands to build the project.'
    )

    text(
      name: 'TEST_COMMANDS',
      defaultValue: '''set -euo pipefail
echo "Test step (optional)"''',
      description: 'Commands to run tests.'
    )

    text(
      name: 'DEPLOY_COMMANDS',
      defaultValue: '''set -euo pipefail
echo "Deploy step (optional)"''',
      description: 'Commands to deploy artifacts.'
    )

    booleanParam(
      name: 'RUN_PREPARE',
      defaultValue: true,
      description: 'Run PREPARE_COMMANDS stage.'
    )

    booleanParam(
      name: 'RUN_BUILD',
      defaultValue: true,
      description: 'Run BUILD_COMMANDS stage.'
    )

    booleanParam(
      name: 'RUN_TEST',
      defaultValue: true,
      description: 'Run TEST_COMMANDS stage.'
    )

    booleanParam(
      name: 'RUN_DEPLOY',
      defaultValue: false,
      description: 'Run DEPLOY_COMMANDS stage.'
    )
  }

  environment {
    PIPELINE_SHELL = "${params.SHELL}"
  }

  stages {
    stage('Checkout') {
      steps {
        script {
          if (params.USE_WORKSPACE_CLEANUP) {
            deleteDir()
          }
        }
        checkout scm
      }
    }

    stage('Prepare') {
      when { expression { return params.RUN_PREPARE } }
      steps {
        script {
          runUserCommands('PREPARE_COMMANDS', params.PREPARE_COMMANDS)
        }
      }
    }

    stage('Build') {
      when { expression { return params.RUN_BUILD } }
      steps {
        script {
          runUserCommands('BUILD_COMMANDS', params.BUILD_COMMANDS)
        }
      }
    }

    stage('Test') {
      when { expression { return params.RUN_TEST } }
      steps {
        script {
          runUserCommands('TEST_COMMANDS', params.TEST_COMMANDS)
        }
      }
    }

    stage('Deploy') {
      when { expression { return params.RUN_DEPLOY } }
      steps {
        script {
          runUserCommands('DEPLOY_COMMANDS', params.DEPLOY_COMMANDS)
        }
      }
    }
  }

  post {
    always {
      script {
        currentBuild.description = [
          "Prepare=${params.RUN_PREPARE}",
          "Build=${params.RUN_BUILD}",
          "Test=${params.RUN_TEST}",
          "Deploy=${params.RUN_DEPLOY}",
          "Shell=${params.SHELL}"
        ].join(' | ')
      }
    }
  }
}

def runUserCommands(String label, String commands) {
  String cmd = (commands ?: '').trim()

  if (!cmd) {
    if (params.FAIL_ON_EMPTY_COMMANDS) {
      error("${label} is empty and FAIL_ON_EMPTY_COMMANDS=true")
    }
    echo("${label} is empty; skipping.")
    return
  }

  if (!params.ALLOW_UNSAFE_COMMANDS) {
    def blockedPatterns = [
      ~/(\s|^)(sudo\s+)?rm\s+-rf\s+\/(\s|$)/,
      ~/(\s|^)(sudo\s+)?rm\s+-rf\s+--no-preserve-root(\s|$)/,
      ~/(\s|^)(sudo\s+)?mkfs(\.\w+)?\s+/,
      ~/(\s|^)(sudo\s+)?dd\s+if=.*\s+of=\/dev\/\w+/,
      ~/(\s|^)(sudo\s+)?shutdown(\s|$)/,
      ~/(\s|^)(sudo\s+)?reboot(\s|$)/,
      ~/(\s|^)(sudo\s+)?poweroff(\s|$)/,
      ~/(\s|^)(sudo\s+)?:\(\)\s*\{\s*:\s*\|\s*:\s*;\s*\}\s*;:/ // fork bomb
    ]
    for (p in blockedPatterns) {
      if ((cmd =~ p).find()) {
        error("Blocked potentially unsafe command in ${label}. Set ALLOW_UNSAFE_COMMANDS=true to override.")
      }
    }
  }

  String scriptBody = cmd.endsWith('\n') ? cmd : (cmd + '\n')

  if (env.PIPELINE_SHELL == 'bash') {
    sh(label: label, shell: '/usr/bin/env bash', script: scriptBody)
  } else {
    sh(label: label, script: scriptBody)
  }
}